public class TryCatchDemo {
    public static void main(String[] args) {
        System.out.println("Before try");
        try {
            System.out.println("In try");
            int result = 10 / 0;             // throws ArithmeticException
            System.out.println("After divide");  // SKIPPED
        } catch (ArithmeticException e) {
            System.out.println("Caught: " + e.getMessage());
        } finally {
            System.out.println("Finally always runs");
        }
        System.out.println("After try-catch");
    }
}
// Output:
// Before try
// In try
// Caught: / by zero
// Finally always runs
// After try-catch

public class MultiCatch {
    public static void riskyMethod(int x) {
        if (x == 0) throw new ArithmeticException("Division by zero");
        if (x < 0) throw new IllegalArgumentException("Negative input");
        int[] arr = new int[x];
        arr[x] = 1;  // always throws ArrayIndexOutOfBoundsException
    }

    public static void main(String[] args) {
        for (int i = 0; i >= 0; i--) {  // i: 0, then -1... but try each case:
        }
        // Demo each case separately:
        test(0);
        test(-1);
        test(3);
    }

    static void test(int x) {
        try {
            riskyMethod(x);
        } catch (ArithmeticException e) {          // most specific first
            System.out.println("Arithmetic: " + e.getMessage());
        } catch (IllegalArgumentException e) {
            System.out.println("IllegalArg: " + e.getMessage());
        } catch (ArrayIndexOutOfBoundsException e) {
            System.out.println("ArrayOOB: index " + x);
        } catch (RuntimeException e) {             // general — catches anything remaining
            System.out.println("Runtime: " + e.getMessage());
        }
    }
}
// test(0)  -> Arithmetic: Division by zero
// test(-1) -> IllegalArg: Negative input
// test(3)  -> ArrayOOB: index 3

public class ThrowsDemo {

    // throws declares this method may throw a checked exception
    public static int divide(int a, int b) throws ArithmeticException {
        if (b == 0)
            throw new ArithmeticException("Cannot divide by zero"); // throw creates & throws
        return a / b;
    }

    // Caller must handle or re-declare
    public static void calculate(int a, int b) {
        try {
            int result = divide(a, b);
            System.out.println(a + " / " + b + " = " + result);
        } catch (ArithmeticException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        calculate(10, 2);  // 10 / 2 = 5
        calculate(10, 0);  // Error: Cannot divide by zero
    }
}

public class FinallyReturn {

    static int method1() {
        try {
            return 1;
        } finally {
            System.out.println("finally1");
            // no return here — finally runs, then 1 is returned
        }
    }

    static int method2() {
        try {
            return 1;
        } finally {
            System.out.println("finally2");
            return 2;  // OVERRIDES the return 1!
        }
    }

    public static void main(String[] args) {
        System.out.println(method1());
        System.out.println(method2());
    }
}
// Output:
// finally1
// 1
// finally2
// 2

// Custom checked exception
class InsufficientFundsException extends Exception {
    private double amount;

    public InsufficientFundsException(double amount) {
        super("Insufficient funds. Short by: " + amount);
        this.amount = amount;
    }

    public double getAmount() { return amount; }
}

class BankAccount {
    private double balance;

    public BankAccount(double balance) { this.balance = balance; }

    public void withdraw(double amount) throws InsufficientFundsException {
        if (amount > balance) {
            throw new InsufficientFundsException(amount - balance);
        }
        balance -= amount;
        System.out.println("Withdrew: " + amount + ". Balance: " + balance);
    }
}

public class CustomExDemo {
    public static void main(String[] args) {
        BankAccount acc = new BankAccount(100.0);
        try {
            acc.withdraw(60.0);
            acc.withdraw(70.0);   // balance now 40, shortfall = 30
        } catch (InsufficientFundsException e) {
            System.out.println("Caught: " + e.getMessage());
            System.out.println("Shortfall: " + e.getAmount());
        }
    }
}
// Output:
// Withdrew: 60.0. Balance: 40.0
// Caught: Insufficient funds. Short by: 30.0
// Shortfall: 30.0

