// Write a method parseInt(String s) that:
// - Returns the integer value if s is a valid integer string
// - Returns 0 if s is null
// - Returns -1 if s is not a valid integer (e.g., "abc", "12.5")
// - Prints a descriptive message for each error case
// Test with: "42", "-7", "abc", null, "12.5"
// Expected output:
// Parsed: 42
// Parsed: -7
// Invalid integer: abc
// Null input received
// Invalid integer: 12.5

sections.solution:
public class SafeParser {
    public static int parseInt(String s) {
        if (s == null) {
            System.out.println("Null input received");
            return 0;
        }
        try {
            int value = Integer.parseInt(s);
            System.out.println("Parsed: " + value);
            return value;
        } catch (NumberFormatException e) {
            System.out.println("Invalid integer: " + s);
            return -1;
        }
    }

    public static void main(String[] args) {
        parseInt("42");
        parseInt("-7");
        parseInt("abc");
        parseInt(null);
        parseInt("12.5");
    }
}
